			const comp = context.lastComponent ?? new Text("", 0, 0);

			if (isPartial) {
				if (text) state.lastFeedText = text;
				comp.setText(text ? theme.fg("warning", text) : theme.fg("warning", "⠋ working..."));
			} else {
				const feedText = state.lastFeedText || text || "✓ done";
				comp.setText(theme.fg("success", feedText));
			}

			return comp;
		},

		async execute(toolCallId, params, signal, onUpdate, ctx) {
			// ── Parallel mode ──
			if (params.tasks) {
				if (params.tasks.length > MAX_PARALLEL) {
					return { content: [{ type: "text", text: `Too many tasks (${params.tasks.length}). Max: ${MAX_PARALLEL}` }], details: {} };
