	// ── Tool: parallel — Multiple tasks simultaneously ────────────────────

	pi.registerTool({
		name: "parallel",
		label: "Parallel Delegation",
		description: `Delegate multiple tasks to specialists in parallel. Each runs in its own isolated in-process session. Use for independent subtasks.`,
		parameters: Type.Object({
			tasks: Type.Array(
				Type.Object({
					specialist: Type.String({ description: "Specialist name: scout, coder, reviewer, researcher, writer" }),
					task: Type.String({ description: "Task description" }),
				}),
				{ description: "Tasks to run in parallel (max 4)" },
			),
		}),

		// ── Render: what shows when tool is invoked ──
		renderCall(args, theme, context) {
			const comp = context.lastComponent ?? new Text("", 0, 0);
			if (args.tasks) {
				const names = args.tasks.map((t: any) => t.specialist).join(", ");
				comp.setText(theme.fg("toolTitle", theme.bold(`parallel [${args.tasks.length}] `)) + theme.fg("dim", names));
			} else {
				comp.setText(theme.fg("toolTitle", theme.bold(`parallel`)));
			}
			return comp;
		},

		// ── Render: what shows during/after execution ──
		renderResult(result, { isPartial, expanded }, theme, context) {
			const state = context.state as any;
			const details = result.details as any;
			const text = result?.content?.[0]?.type === "text" ? result.content[0].text : "";

			if (isPartial && !state.interval) {
				state.interval = setInterval(() => context.invalidate(), 1000);
			}
			if (!isPartial && state.interval) {
				clearInterval(state.interval);
				state.interval = undefined;
			}

			const comp = context.lastComponent ?? new Text("", 0, 0);

			if (isPartial) {
				if (text) state.lastFeedText = text;
				comp.setText(text ? theme.fg("warning", text) : theme.fg("warning", "⠋ Running..."));
			} else {
				const feedText = state.lastFeedText || text || "✓ done";
				comp.setText(theme.fg("success", details?.results
					? `✓ ${details.results.filter((r: any) => !r.error).length}/${details.results.length} completed`
					: feedText));
			}

			return comp;
		},

		async execute(toolCallId, params, signal, onUpdate, ctx) {
			if (params.tasks.length > MAX_PARALLEL) {
				return {
					content: [{ type: "text", text: `Too many tasks (${params.tasks.length}). Max: ${MAX_PARALLEL}` }],
					details: {},
				};
			}

			const resolved = params.tasks
				.map((t) => {
					const spec = SPECIALISTS[t.specialist];
					if (!spec) return null;
					return { specialist: spec, task: t.task };
				})
				.filter(Boolean) as Array<{ specialist: Specialist; task: string }>;

			if (resolved.length === 0) {
				return {
					content: [{ type: "text", text: "No valid specialists found." }],
					details: {},
				};
			}

			// Reset and create fresh orchestrator activity
			resetOrchestratorActivity();
			const taskLabels = resolved.map((r) => shortenLabel(r.task));
			setupPlanPanel(orchestratorGoal || taskLabels.join(", "), taskLabels, ctx);
			const activity = getOrchestratorActivity();
			for (const task of resolved) {
				addOrchestratorStep(activity, task.task);
			}

			// Stream orchestrator progress
			onUpdate?.({
				content: [{ type: "text", text: renderOrchestratorActivity(activity, orchestratorGoal) }],
				details: { status: "running", count: resolved.length },
			});

			const results = await runParallel(resolved, ctx.cwd, { modelRegistry: ctx.modelRegistry, model: ctx.model }, signal, onUpdate);

			// Mark all steps complete
			for (const _ of resolved) {
				completeOrchestratorStep(activity);
				completePlanStep(ctx);
			}

			// Final update — store feed text in details for renderResult
			const _parallelFeed = renderOrchestratorActivity(activity, orchestratorGoal);
			onUpdate?.({
				content: [{ type: "text", text: _parallelFeed }],
				details: { status: "done" },
			});

			const output = results
				.map((r) => {
					const status = r.error ? "ERROR" : "OK";
					return `### [${r.specialist}] ${status}\n\n${r.output}`;
				})
				.join("\n\n---\n\n");

			return {
				content: [{ type: "text", text: output }],
				details: {
					status: "done",
					activityFeed: _parallelFeed,
					results: results.map((r) => ({
						specialist: r.specialist,
						outputLength: r.output.length,
						error: r.error,
					})),
				},
			};
		},
	});

