edits.newText:
// ── Safety net: Block non-delegation tool calls ──────────────────────
// Only blocks in the main session — _inSubagentExecution guard prevents
// interfering with subagent tool execution.
pi.on("tool_call", async (event, ctx) => {
	if (_inSubagentExecution > 0) return; // Don't block subagent tools
	if (event.toolName !== "delegate" && event.toolName !== "chain") {
		return { block: true, reason: `Orchestrator mode: use delegate() or chain() instead of ${event.toolName}` };
	}
});

